 NULL) OR (`ods`.`ods_book_user_payorder`.`SystemType` = ''), -99, `ods`.`ods_book_user_payorder`.`SystemType`) AS `SystemType`, if((`ods`.`ods_book_user_payorder`.`ReceiveDate` IS NULL) OR (`ods`.`ods_book_user_payorder`.`ReceiveDate` = ''), '1970-01-01 00:00:00', `ods`.`ods_book_user_payorder`.`ReceiveDate`) AS `ReceiveDate`, if((`ods`.`ods_book_user_payorder`.`MT` IS NULL) OR (`ods`.`ods_book_user_payorder`.`MT` = ''), -99, `ods`.`ods_book_user_payorder`.`MT`) AS `MT`, if((`ods`.`ods_book_user_payorder`.`CouponId` IS NULL) OR (`ods`.`ods_book_user_payorder`.`CouponId` = ''), -99, `ods`.`ods_book_user_payorder`.`CouponId`) AS `CouponId`, if((`ods`.`ods_book_user_payorder`.`PackageId` IS NULL) OR (`ods`.`ods_book_user_payorder`.`PackageId` = ''), -99, `ods`.`ods_book_user_payorder`.`PackageId`) AS `PackageId`, if((`ods`.`ods_book_user_payorder`.`ShopItem` IS NULL) OR (`ods`.`ods_book_user_payorder`.`ShopItem` = ''), -99, `ods`.`ods_book_user_payorder`.`ShopItem`) AS `ShopItem`, if((`ods`.`ods_book_user_payorder`.`ExtInfo` IS NULL) OR (`ods`.`ods_book_user_payorder`.`ExtInfo` = ''), -99, `ods`.`ods_book_user_payorder`.`ExtInfo`) AS `ExtInfo`, if((`ods`.`ods_book_user_payorder`.`VipExpireTime` IS NULL) OR (`ods`.`ods_book_user_payorder`.`VipExpireTime` = ''), -99, `ods`.`ods_book_user_payorder`.`VipExpireTime`) AS `VipExpireTime`, if((`ods`.`ods_book_user_payorder`.`RealMoney` IS NULL) OR (`ods`.`ods_book_user_payorder`.`RealMoney` = ''), -99, `ods`.`ods_book_user_payorder`.`RealMoney`) AS `RealMoney`, if((`ods`.`ods_book_user_payorder`.`GiveMoney` IS NULL) OR (`ods`.`ods_book_user_payorder`.`GiveMoney` = ''), -99, `ods`.`ods_book_user_payorder`.`GiveMoney`) AS `AwardMoney`, if((`ods`.`ods_book_user_payorder`.`PayConfigId` IS NULL) OR (`ods`.`ods_book_user_payorder`.`PayConfigId` = ''), -99, `ods`.`ods_book_user_payorder`.`PayConfigId`) AS `PayConfigId`, if((`ods`.`ods_book_user_payorder`.`CoreVer` IS NULL) OR (`ods`.`ods_book_user_payorder`.`CoreVer` = ''), -99, `ods`.`ods_book_user_payorder`.`CoreVer`) AS `CoreVer`, if((`ods`.`ods_book_user_payorder`.`UniqueGuid` IS NULL) OR (`ods`.`ods_book_user_payorder`.`UniqueGuid` = ''), -99, `ods`.`ods_book_user_payorder`.`UniqueGuid`) AS `DeviceGUID`, if((`ods`.`ods_book_user_payorder`.`TestFlag` IS NULL) OR (`ods`.`ods_book_user_payorder`.`TestFlag` = ''), -99, `ods`.`ods_book_user_payorder`.`TestFlag`) AS `TestFlag`, if((`ods`.`ods_book_user_payorder`.`BaseAmount` IS NULL) OR (`ods`.`ods_book_user_payorder`.`BaseAmount` = ''), -99, `ods`.`ods_book_user_payorder`.`BaseAmount`) AS `BaseAmount`, if((`ods`.`ods_book_user_payorder`.`Version` IS NULL) OR (`ods`.`ods_book_user_payorder`.`Version` = ''), -99, `ods`.`ods_book_user_payorder`.`Version`) AS `Version`, if((`ods`.`ods_book_user_payorder`.`SubPayType` IS NULL) OR (`ods`.`ods_book_user_payorder`.`SubPayType` = ''), -99, `ods`.`ods_book_user_payorder`.`SubPayType`) AS `SubPayType`, if((`ods`.`ods_book_user_payorder`.`GiftMoney` IS NULL) OR (`ods`.`ods_book_user_payorder`.`GiftMoney` = ''), -99, `ods`.`ods_book_user_payorder`.`GiftMoney`) AS `GiftMoney`, if((`ods`.`ods_book_user_payorder`.`OrderInitTime` IS NULL) OR (`ods`.`ods_book_user_payorder`.`OrderInitTime` = ''), '1970-01-01 00:00:00', `ods`.`ods_book_user_payorder`.`OrderInitTime`) AS `OrderInitTime`, if((`ods`.`ods_book_user_payorder`.`CooOrderExtInfo` IS NULL) OR (`ods`.`ods_book_user_payorder`.`CooOrderExtInfo` = ''), -99, `ods`.`ods_book_user_payorder`.`CooOrderExtInfo`) AS `CooOrderExtInfo`, `ods`.`ods_book_user_payorder`.`ProductData` AS `product_data`, now() AS `etl_time`
FROM `ods`.`ods_book_user_payorder`
WHERE (((`ods`.`ods_book_user_payorder`.`dt` >= '2024-09-01') AND ((`ods`.`ods_book_user_payorder`.`PackageId` LIKE '%Ps_Half%') OR (`ods`.`ods_book_user_payorder`.`PackageId` LIKE '%Ps_Shop_half%'))) OR (`ods`.`ods_book_user_payorder`.`dt` >= '2025-03-06')) AND (`ods`.`ods_book_user_payorder`.`TestFlag` = 0);
